import{_ as o}from"./chunks/ProjectDetails.DJkSSHiL.js";import{_ as t,o as a,c as s,ae as r}from"./chunks/framework.C00B0EYs.js";const h=JSON.parse('{"title":"项目详情与保存","description":"查看项目元数据、统计信息、保存行为与历史控制。","frontmatter":{"title":"项目详情与保存","description":"查看项目元数据、统计信息、保存行为与历史控制。"},"headers":[],"relativePath":"zh/docs/guide/project-details-and-save.md","filePath":"zh/docs/guide/project-details-and-save.md"}'),i={name:"zh/docs/guide/project-details-and-save.md"};function l(n,e,d,c,p,_){return a(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="项目详情与保存" tabindex="-1">项目详情与保存 <a class="header-anchor" href="#项目详情与保存" aria-label="Permalink to &quot;项目详情与保存&quot;">​</a></h1><p>本页说明项目详情弹窗中可以查看的信息、<code>.msep</code> 项目格式的作用，以及保存与未保存变更的当前行为。</p><h2 id="_1-项目详情" tabindex="-1">1. 项目详情 <a class="header-anchor" href="#_1-项目详情" aria-label="Permalink to &quot;1. 项目详情&quot;">​</a></h2><p><img src="'+o+'" alt="项目信息"></p><p><strong>Project Details</strong> 会展示当前工程的项目名称和一组统计信息。当前实现中：</p><ul><li><strong>可编辑项</strong>：项目名称。</li><li><strong>只读信息</strong>：文件路径、轨道数、音频资源数、已分配音频数、关键帧总数、最高速度、加速度、制动减速度、创建时间和更新时间。</li></ul><p>这些信息有助于你在继续编辑或准备导出前确认当前工程状态。</p><h2 id="_2-msep-文件格式" tabindex="-1">2. <code>.msep</code> 文件格式 <a class="header-anchor" href="#_2-msep-文件格式" aria-label="Permalink to &quot;2. `.msep` 文件格式&quot;">​</a></h2><p>Motor Sound Editor 使用 <code>.msep</code> 作为专属工程文件格式。</p><ul><li><strong>一体化打包</strong>：<code>.msep</code> 会把项目元数据、轨道定义、曲线数据和已打包的音频资源一起保存。</li><li><strong>便于迁移</strong>：分享或移动 <code>.msep</code> 时，不需要额外整理一组松散的音频文件。</li><li><strong>持续编辑</strong>：<code>.msep</code> 是可编辑源文件，而不是最终交付包。</li></ul><h2 id="_3-保存与未保存提示" tabindex="-1">3. 保存与未保存提示 <a class="header-anchor" href="#_3-保存与未保存提示" aria-label="Permalink to &quot;3. 保存与未保存提示&quot;">​</a></h2><ul><li><strong>未保存状态</strong>：当你添加轨道、修改关键帧、替换音频或更新项目名称时，项目会进入未保存状态。</li><li><strong>保存（Save）</strong>：把当前文档与音频打包写回原来的 <code>.msep</code> 文件。</li><li><strong>另存为（Save As）</strong>：将当前工程写入新的 <code>.msep</code> 文件副本。</li><li><strong>离开前提示</strong>：如果项目存在未保存改动，返回首页或关闭窗口前会弹出保存确认。</li><li><strong>撤销与重做</strong>：保存不会清空当前会话内的撤销 / 重做历史；只要应用未关闭，你仍可继续回退近期操作。</li></ul>',12)])])}const u=t(i,[["render",l]]);export{h as __pageData,u as default};
